224→private struct LiquidGlassInputContent: View {
225→  var value: String
226→  var label: String?
227→  var placeholder: String
228→  var leadingSystemImage: String?
229→  var showClearButton: Bool
230→  var variant: String
231→  var selectedTags: [LiquidGlassSelectedTag]
232→  var autoFocus: Bool
233→  var focusedOverride: Bool?
234→  var returnKeyType: String
235→  var blurOnSubmit: Bool
236→  var onChangeText: (String) -> Void
237→  var onClear: () -> Void
238→  var onTagPress: (String) -> Void
239→  var onFocus: () -> Void
240→  var onBlur: () -> Void
241→  var onSubmitEditing: () -> Void
242→  
243→  @State private var text: String = ""
244→  @State private var isTextInputFocused: Bool = false
245→  @Environment(\.colorScheme) private var colorScheme
246→
247→  private var shouldShowTags: Bool {
248→    variant == "tags" || variant == "mixed"
249→  }
250→
251→  private var shouldShowTextField: Bool {
252→    variant == "text" || variant == "mixed"
253→  }
254→
255→  private var shouldUseAccent: Bool {
256→    shouldShowTags && !selectedTags.isEmpty && !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
257→  }
258→
259→  private var shouldUseCapsuleShape: Bool {
260→    variant == "tags" || variant == "mixed"
261→  }
262→
263→  private var hasClearableContent: Bool {
264→    !value.isEmpty || !selectedTags.isEmpty
265→  }
266→
267→  private var uiReturnKeyType: UIReturnKeyType {
268→    switch returnKeyType {
269→    case "next":
270→      return .next
271→    case "search":
272→      return .search
273→    default:
274→      return .done
275→    }
276→  }
277→
278→  private var effectiveIsFocused: Bool {
279→    focusedOverride ?? isTextInputFocused
280→  }
281→  
282→  var body: some View {
283→    Group {
284→      if let labelText = label, !labelText.isEmpty, variant == "text" {
285→        VStack(alignment: .leading, spacing: 8) {
286→          Text(labelText)
287→            .font(.system(size: 16, weight: .medium))
288→            .foregroundStyle(.primary)
289→
290→          inputContainer
291→        }
292→      } else {
293→        inputContainer
294→      }
295→    }
296→    .onAppear {
297→      text = value
298→      if autoFocus && focusedOverride == nil {
299→        isTextInputFocused = true
300→      }
301→    }
302→    .onChange(of: value) { _, newValue in
303→      if text != newValue {
304→        text = newValue
305→      }
306→    }
307→  }
308→
309→  @ViewBuilder
310→  private var inputRow: some View {
311→    HStack(spacing: 4) {
312→      if let imageName = leadingSystemImage {
313→        Image(systemName: imageName)
314→          .font(.system(size: 20))
315→          .foregroundStyle(.primary)
316→      }
317→
318→      inlineContent
319→
320→      if showClearButton && hasClearableContent {
321→        Button(action: {
322→          text = ""
323→          onClear()
324→          onChangeText("")
325→        }) {
326→          Image(systemName: "xmark.circle.fill")
327→            .font(.system(size: 20))
328→            .foregroundStyle(.secondary)
329→        }
330→        .buttonStyle(.plain)
331→      }
332→    }
333→    .onChange(of: text) { _, newValue in
334→      onChangeText(newValue)
335→    }
336→  }
337→
338→  private var inputContainer: some View {
339→    inputRow
340→      .frame(maxWidth: .infinity, maxHeight: .infinity)
341→      .padding(.horizontal, 8)
342→      .background {
343→        RoundedRectangle(cornerRadius: 24)
344→          .fill(.ultraThinMaterial)
345→      }
346→  }
347→
348→  @ViewBuilder
349→  private var inlineContent: some View {
350→    if shouldShowTags || shouldShowTextField {
351→      ScrollViewReader { scrollProxy in
352→        ScrollView(.horizontal, showsIndicators: false) {
353→          HStack(spacing: 6) {
354→            if shouldShowTags {
355→              ForEach(selectedTags) { tag in
356→                Button(action: {
357→                  onTagPress(tag.id)
358→                }) {
359→                  Text(tag.label)
360→                    .font(.system(size: 14, weight: .medium))
361→                    .foregroundStyle(
362→                      shouldUseAccent
363→                        ? accentPillTextColor
364→                        : .primary
365→                    )
366→                    .padding(.horizontal, 4)
367→                    .padding(.vertical, 4)
368→                    .background(
369→                      RoundedRectangle(cornerRadius: 8, style: .continuous)
370→                        .fill(
371→                          shouldUseAccent
372→                            ? accentPillBackgroundColor
373→                            : Color(white: 0.82, opacity: 0.75)
374→                        )
375→                    )
376→                }
377→                .buttonStyle(.plain)
378→                .accessibilityLabel(tag.accessibilityLabel ?? tag.label)
379→              }
380→            }
381→
382→            if shouldShowTextField {
383→              BackspaceAwareTextField(
384→                text: $text,
385→                placeholder: placeholder,
386→                returnKeyType: uiReturnKeyType,
387→                isFocused: Binding(
388→                  get: {
389→                    effectiveIsFocused
